  1→// ── Session store (signal-based) ─────────────────────────────
  2→//
  3→// Single source of truth for session data. Each session becomes a
  4→// Session class instance with per-session signals for client-side state.
  5→
  6→import { computed, signal } from "@preact/signals";
  7→
  8→// ── Session class ────────────────────────────────────────────
  9→
 10→export class Session {
 11→	constructor(serverData) {
 12→		// Server fields (plain properties, set on construction/update)
 13→		this.key = serverData.key;
 14→		this.label = serverData.label || "";
 15→		this.model = serverData.model || "";
 16→		this.provider = serverData.provider || "";
 17→		this.projectId = serverData.projectId || "";
 18→		this.messageCount = serverData.messageCount || 0;
 19→		this.lastSeenMessageCount = serverData.lastSeenMessageCount || 0;
 20→		this.preview = serverData.preview || "";
 21→		this.updatedAt = serverData.updatedAt || 0;
 22→		this.createdAt = serverData.createdAt || 0;
 23→		this.worktree_branch = serverData.worktree_branch || "";
 24→		this.sandbox_enabled = serverData.sandbox_enabled;
 25→		this.sandbox_image = serverData.sandbox_image || null;
 26→		this.channelBinding = serverData.channelBinding || null;
 27→		this.parentSessionKey = serverData.parentSessionKey || "";
 28→		this.forkPoint = serverData.forkPoint != null ? serverData.forkPoint : null;
 29→		this.agent_id = serverData.agent_id || "main";
 30→		this.node_id = serverData.node_id || null;
 31→		this.mcpDisabled = serverData.mcpDisabled;
 32→		this.archived = serverData.archived;
 33→		this.activeChannel = serverData.activeChannel;
 34→		this.version = serverData.version || 0;
 35→
 36→		// Client signals (reactive, per-session)
 37→		this.replying = signal(false);
 38→		this.localUnread = signal(false);
 39→		this.streamText = signal("");
 40→		this.voicePending = signal(false);
 41→		this.activeRunId = signal(null);
 42→		this.lastHistoryIndex = signal(-1);
 43→		this.sessionTokens = signal({ input: 0, output: 0 });
 44→		this.contextWindow = signal(0);
 45→		this.toolsEnabled = signal(true);
 46→		this.lastToolOutput = signal("");
 47→		// Total message count — reactive signal that drives the sidebar badge.
 48→		// Components read this to show/hide badge and compute unread tinting.
 49→		this.badgeCount = signal(this.messageCount);
 50→		// Bumped whenever plain properties change so subscribed components re-render.
 51→		this.dataVersion = signal(0);
 52→	}
 53→
 54→	/** Recalculate badge from current messageCount. */
 55→	updateBadge() {
 56→		this.badgeCount.value = this.messageCount;
 57→	}
 58→
 59→	/** Merge server fields, preserving client signals. Returns false if stale. */
 60→	update(serverData) {
 61→		var incoming = serverData.version || 0;
 62→		if (incoming > 0 && this.version > 0 && incoming < this.version) return false;
 63→		this.version = incoming || this.version;
 64→		this.label = serverData.label || "";
 65→		this.model = serverData.model || "";
 66→		this.provider = serverData.provider || "";
 67→		this.projectId = serverData.projectId || "";
 68→		// Only accept server counts when they've caught up with optimistic
 69→		// client bumps. Authoritative resets (/clear, switchSession) use
 70→		// syncCounts() which sets messageCount directly before any fetch.
 71→		var serverCount = serverData.messageCount || 0;
 72→		if (serverCount >= this.messageCount) {
 73→			this.messageCount = serverCount;
 74→			this.lastSeenMessageCount = serverData.lastSeenMessageCount || 0;
 75→			this.preview = serverData.preview || "";
 76→			this.updatedAt = serverData.updatedAt || 0;
 77→		}
 78→		this.createdAt = serverData.createdAt || 0;
 79→		this.worktree_branch = serverData.worktree_branch || "";
 80→		this.sandbox_enabled = serverData.sandbox_enabled;
 81→		this.sandbox_image = serverData.sandbox_image || null;
 82→		this.channelBinding = serverData.channelBinding || null;
 83→		this.parentSessionKey = serverData.parentSessionKey || "";
 84→		this.forkPoint = serverData.forkPoint != null ? serverData.forkPoint : null;
 85→		this.agent_id = serverData.agent_id || "main";
 86→		this.node_id = serverData.node_id || null;
 87→		this.mcpDisabled = serverData.mcpDisabled;
 88→		this.archived = serverData.archived;
 89→		this.activeChannel = serverData.activeChannel;
 90→		this.updateBadge();
 91→		this.dataVersion.value++;
 92→		return true;
 93→	}
 94→
 95→	/** Optimistic bump: increment total and mark seen if active. */
 96→	bumpCount(increment) {
 97→		this.messageCount = (this.messageCount || 0) + increment;
 98→		if (this.key === activeSessionKey.value) {
 99→			this.lastSeenMessageCount = this.messageCount;
100→		}
101→		this.updateBadge();
102→	}
103→
104→	/** Authoritative set (switchSession history, /clear). */
105→	syncCounts(messageCount, lastSeenMessageCount) {
106→		this.messageCount = messageCount;
107→		this.lastSeenMessageCount = lastSeenMessageCount;
108→		this.updateBadge();
109→	}
110→
111→	/** Clear streaming state for this session. */
112→	resetStreamState() {
113→		this.streamText.value = "";
114→		this.voicePending.value = false;
115→		this.activeRunId.value = null;
116→		this.lastToolOutput.value = "";
117→	}
118→}
119→
120→// ── Store signals ────────────────────────────────────────────
121→export var sessions = signal([]);
122→export var activeSessionKey = signal(localStorage.getItem("moltis-session") || "main");
123→export var switchInProgress = signal(false);
124→export var refreshInProgressKey = signal("");
125→/** Session list tab filter: "all" | "sessions" | "cron" */
126→export var sessionListTab = signal(localStorage.getItem("moltis-session-tab") || "sessions");
127→
128→export var activeSession = computed(() => {
129→	var key = activeSessionKey.value;
130→	return sessions.value.find((s) => s.key === key) || null;
131→});
132→
133→export function compareSessionOrder(left, right) {
134→	var leftKey = left?.key || "";
135→	var rightKey = right?.key || "";
136→	var leftMain = leftKey === "main";
137→	var rightMain = rightKey === "main";
138→	if (leftMain !== rightMain) return leftMain ? -1 : 1;
139→
140→	var updatedDiff = (Number(right?.updatedAt) || 0) - (Number(left?.updatedAt) || 0);
141→	if (updatedDiff !== 0) return updatedDiff;
142→
143→	var createdDiff = (Number(right?.createdAt) || 0) - (Number(left?.createdAt) || 0);
144→	if (createdDiff !== 0) return createdDiff;
145→
146→	return leftKey.localeCompare(rightKey);
147→}
148→
149→export function insertSessionInOrder(list, session) {
150→	if (!session?.key) return Array.isArray(list) ? list.slice() : [];
151→	var result = Array.isArray(list) ? list.filter((entry) => entry?.key !== session.key) : [];
152→	result.push(session);
153→	result.sort(compareSessionOrder);
154→	return result;
155→}
156→
157→// ── Methods ──────────────────────────────────────────────────
158→
159→/**
160→ * Replace the full sessions list from server data.
161→ * Reuses existing Session instances (matched by key) so their
162→ * client-side signals (replying, localUnread, streamText) are preserved.
163→ * New keys get fresh instances. Missing keys are dropped.
164→ */
165→export function setAll(serverSessions) {
166→	var existing = {};
167→	for (var s of sessions.value) {
168→		existing[s.key] = s;
169→	}
170→
171→	var result = [];
172→	for (var data of serverSessions) {
173→		var prev = existing[data.key];
174→		if (prev) {
175→			prev.update(data);
176→			// Preserve client-side flags from old patched objects
177→			if (data._localUnread) prev.localUnread.value = true;
178→			if (data._replying || data.replying) prev.replying.value = true;
179→			result.push(prev);
180→		} else {
181→			var session = new Session(data);
182→			if (data._localUnread) session.localUnread.value = true;
183→			if (data._replying || data.replying) session.replying.value = true;
184→			result.push(session);
185→		}
186→	}
187→
188→	sessions.value = result;
189→}
190→
191→/**
192→ * Upsert a single session from server data.
193→ * Reuses existing instance when present; creates and appends when missing.
194→ */
195→export function upsert(serverData) {
196→	if (!serverData?.key) return null;
197→	var prev = getByKey(serverData.key);
198→	if (prev) {
199→		prev.update(serverData);
200→		sessions.value = insertSessionInOrder(sessions.value, prev);
201→		return prev;
202→	}
203→	var next = new Session(serverData);
204→	sessions.value = insertSessionInOrder(sessions.value, next);
205→	return next;
206→}
207→
208→/** Remove a session by key. Returns true when a session was removed. */
209→export function remove(key) {
210→	if (!key) return false;
211→	var existing = getByKey(key);
212→	if (!existing) return false;
213→	sessions.value = sessions.value.filter((session) => session.key !== key);
214→	if (activeSessionKey.value === key) {
215→		var fallback = sessions.value.find((session) => session.key === "main")?.key || sessions.value[0]?.key || "main";
216→		activeSessionKey.value = fallback;
217→		localStorage.setItem("moltis-session", fallback);
218→	}
219→	return true;
220→}
221→
222→/** Fetch sessions from the server via HTTP (gzip-friendly). */
223→export function fetch() {
224→	return window
225→		.fetch("/api/sessions", {
226→			headers: { Accept: "application/json" },
227→		})
228→		.then((response) => (response.ok ? response.json() : null))
229→		.then((payload) => {
230→			if (!Array.isArray(payload)) return;
231→			setAll(payload);
232→		})
233→		.catch(() => {});
234→}
235→
236→/** Notify Preact that session data changed (triggers re-render). */
237→export function notify() {
238→	sessions.value = [...sessions.value];
239→}
240→
241→/** Look up a session by key. */
242→export function getByKey(key) {
243→	return sessions.value.find((s) => s.key === key) || null;
244→}
245→
246→/** Set the active session key. Persists to localStorage. */
247→export function setActive(key) {
248→	activeSessionKey.value = key;
249→	localStorage.setItem("moltis-session", key);
250→}
251→
252→/** Set the session list tab and persist it. */
253→export function setSessionListTab(tab) {
254→	sessionListTab.value = tab;
255→	localStorage.setItem("moltis-session-tab", tab);
256→}
257→
258→export var sessionStore = {
259→	sessions,
260→	activeSessionKey,
261→	activeSession,
262→	switchInProgress,
263→	refreshInProgressKey,
264→	sessionListTab,
265→	Session,
266→	setAll,
267→	upsert,
268→	remove,
269→	fetch,
270→	getByKey,
271→	setActive,
272→	setSessionListTab,
273→	notify,
274→};
