301:export function markSessionLocallyCleared(key) {
332:/** Clear history for the currently active session and reset local UI state. */
333:export function clearActiveSession() {
338:	return sendRpc("chat.clear", {}).then((res) => {
345:			markSessionLocallyCleared(activeKey);
346:			clearSessionHistory(activeKey);
347:			clearHistoryPaginationState(activeKey);
352:		chatAddMsg("error", res?.error?.message || "Clear failed");
437:function clearHistoryPaginationState(key) {
439:		sessionHistoryPaging.clear();
443:	sessionHistoryPaging.delete(key);
525:export function clearSessionHistoryCache(key) {
